namespace RecipeHub.Models;

public class Recipe
{
    public int Id { get; set; }
    public string Title { get; set; } = string.Empty;
    public string Category { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public List<string> Ingredients { get; set; } = [];
    public List<string> Steps { get; set; } = [];
    public string ImageUrl { get; set; } = string.Empty;
    public int TotalRatings { get; set; }
    public int RatingSum { get; set; }
    public double AverageRating => TotalRatings > 0 ? (double)RatingSum / TotalRatings : 0;
}

public class RecipeSubmission
{
    public string Title { get; set; } = string.Empty;
    public string Category { get; set; } = string.Empty;
    public string Ingredients { get; set; } = string.Empty;
    public string Steps { get; set; } = string.Empty;
}

using RecipeHub.Models;

namespace RecipeHub.Services;

public class RecipeService
{
    private readonly List<Recipe> _recipes =
    [
        new()
        {
            Id = 1, Title = "Classic Margherita Pizza", Category = "Italian",
            Description = "A simple, classic pizza with fresh mozzarella, tomatoes, and basil.",
            Ingredients = ["Pizza dough", "San Marzano tomatoes", "Fresh mozzarella", "Fresh basil", "Olive oil", "Salt"],
            Steps = ["Preheat oven to 475°F.", "Roll out dough on a floured surface.", "Spread crushed tomatoes over dough.", "Tear mozzarella and distribute evenly.", "Bake for 10–12 minutes until crust is golden.", "Top with fresh basil and a drizzle of olive oil."],
            ImageUrl = "🍕", TotalRatings = 24, RatingSum = 108
        },
        new()
        {
            Id = 2, Title = "Spaghetti Carbonara", Category = "Italian",
            Description = "Creamy Roman pasta made with eggs, cheese, pancetta, and pepper.",
            Ingredients = ["Spaghetti", "Pancetta", "Eggs", "Pecorino Romano", "Black pepper", "Salt"],
            Steps = ["Cook spaghetti in salted boiling water.", "Fry pancetta until crispy.", "Whisk eggs with grated Pecorino and pepper.", "Drain pasta, reserving some water.", "Toss hot pasta with pancetta, then egg mixture off heat.", "Serve immediately with extra cheese and pepper."],
            ImageUrl = "🍝", TotalRatings = 18, RatingSum = 85
        },
        new()
        {
            Id = 3, Title = "Chicken Tikka Masala", Category = "Indian",
            Description = "Tender chicken pieces in a rich, spiced tomato-cream sauce.",
            Ingredients = ["Chicken breast", "Yogurt", "Garam masala", "Tomato sauce", "Heavy cream", "Onion", "Garlic", "Ginger"],
            Steps = ["Marinate chicken in yogurt and spices for 1 hour.", "Grill or broil chicken until charred.", "Sauté onion, garlic, and ginger.", "Add tomato sauce and simmer.", "Stir in cream and garam masala.", "Add chicken pieces and simmer 10 minutes."],
            ImageUrl = "🍛", TotalRatings = 30, RatingSum = 140
        },
        new()
        {
            Id = 4, Title = "Vegetable Pad Thai", Category = "Thai",
            Description = "Sweet, sour, and savory stir-fried noodles with fresh vegetables.",
            Ingredients = ["Rice noodles", "Tofu", "Bean sprouts", "Peanuts", "Lime", "Tamarind paste", "Fish sauce", "Sugar", "Eggs"],
            Steps = ["Soak rice noodles in warm water for 30 minutes.", "Mix tamarind paste, fish sauce, and sugar for the sauce.", "Stir-fry tofu until golden.", "Push tofu aside, scramble eggs in the pan.", "Add drained noodles and sauce, toss well.", "Serve with bean sprouts, crushed peanuts, and lime wedges."],
            ImageUrl = "🍜", TotalRatings = 15, RatingSum = 68
        },
        new()
        {
            Id = 5, Title = "Beef Tacos", Category = "Mexican",
            Description = "Seasoned ground beef in corn tortillas with fresh toppings.",
            Ingredients = ["Ground beef", "Corn tortillas", "Lettuce", "Tomato", "Cheese", "Sour cream", "Taco seasoning"],
            Steps = ["Brown ground beef in a skillet.", "Add taco seasoning and water, simmer.", "Warm tortillas in a dry pan.", "Fill tortillas with seasoned beef.", "Top with lettuce, tomato, cheese, and sour cream.", "Serve with salsa and lime."],
            ImageUrl = "🌮", TotalRatings = 22, RatingSum = 95
        },
        new()
        {
            Id = 6, Title = "Guacamole", Category = "Mexican",
            Description = "Fresh, creamy avocado dip with lime and cilantro.",
            Ingredients = ["Avocados", "Lime juice", "Cilantro", "Red onion", "Jalapeño", "Salt", "Tomato"],
            Steps = ["Halve and pit avocados, scoop into bowl.", "Mash to desired consistency.", "Stir in diced onion, jalapeño, and tomato.", "Add lime juice, cilantro, and salt.", "Taste and adjust seasoning.", "Serve immediately with tortilla chips."],
            ImageUrl = "🥑", TotalRatings = 12, RatingSum = 55
        },
        new()
        {
            Id = 7, Title = "Miso Soup", Category = "Japanese",
            Description = "Light, savory broth with tofu, seaweed, and green onion.",
            Ingredients = ["Dashi stock", "Miso paste", "Silken tofu", "Wakame seaweed", "Green onions"],
            Steps = ["Bring dashi stock to a gentle simmer.", "Dissolve miso paste in a ladle of warm dashi.", "Add dissolved miso back to the pot.", "Add cubed tofu and rehydrated wakame.", "Heat gently — do not boil.", "Serve topped with sliced green onions."],
            ImageUrl = "🍲", TotalRatings = 10, RatingSum = 42
        },
        new()
        {
            Id = 8, Title = "Chocolate Lava Cake", Category = "Desserts",
            Description = "Rich individual chocolate cakes with a molten center.",
            Ingredients = ["Dark chocolate", "Butter", "Eggs", "Sugar", "Flour", "Vanilla extract"],
            Steps = ["Preheat oven to 425°F. Butter and flour ramekins.", "Melt chocolate and butter together.", "Whisk eggs and sugar until thick.", "Fold chocolate mixture into eggs.", "Add flour and vanilla, fold gently.", "Bake 12–14 minutes until edges are firm but center is soft."],
            ImageUrl = "🍫", TotalRatings = 28, RatingSum = 134
        },
    ];

    public IReadOnlyList<string> GetCategories() =>
        _recipes.Select(r => r.Category).Distinct().OrderBy(c => c).ToList();

    public IReadOnlyList<Recipe> GetByCategory(string category) =>
        _recipes.Where(r => r.Category.Equals(category, StringComparison.OrdinalIgnoreCase)).ToList();

    public Recipe? GetById(int id) => _recipes.FirstOrDefault(r => r.Id == id);

    public void AddRating(int recipeId, int stars)
    {
        var recipe = GetById(recipeId);
        if (recipe is not null && stars is >= 1 and <= 5)
        {
            recipe.TotalRatings++;
            recipe.RatingSum += stars;
        }
    }

    public void AddRecipe(RecipeSubmission submission)
    {
        var recipe = new Recipe
        {
            Id = _recipes.Count > 0 ? _recipes.Max(r => r.Id) + 1 : 1,
            Title = submission.Title,
            Category = submission.Category,
            Description = $"A community-submitted {submission.Category} recipe.",
            Ingredients = submission.Ingredients.Split('\n', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries).ToList(),
            Steps = submission.Steps.Split('\n', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries).ToList(),
            ImageUrl = "📝"
        };
        _recipes.Add(recipe);
    }
}

