@page "/category/{CategoryName}"
@using RecipeHub.Models
@using RecipeHub.Services

<PageTitle>@CategoryName Recipes — RecipeHub</PageTitle>

<h1>@CategoryName Recipes</h1>

<nav aria-label="breadcrumb" class="mb-3">
    <ol class="breadcrumb">
        <li class="breadcrumb-item"><a href="/">Home</a></li>
        <li class="breadcrumb-item active">@CategoryName</li>
    </ol>
</nav>

@if (Recipes.Count == 0)
{
    <div class="alert alert-info">No recipes found in this category.</div>
}
else
{
    <div class="row">
        @foreach (var recipe in Recipes)
        {
            <div class="col-md-6 mb-4">
                <div class="card h-100 shadow-sm">
                    <div class="card-body">
                        <div class="d-flex align-items-center mb-2">
                            <span class="fs-1 me-3">@recipe.ImageUrl</span>
                            <div>
                                <h4 class="card-title mb-1">@recipe.Title</h4>
                                <small class="text-muted">
                                    ⭐ @recipe.AverageRating.ToString("F1") (@recipe.TotalRatings ratings)
                                </small>
                            </div>
                        </div>
                        <p class="card-text">@recipe.Description</p>
                        <a href="recipe/@recipe.Id" class="btn btn-primary">View Recipe</a>
                    </div>
                </div>
            </div>
        }
    </div>
}

@code {
    [Parameter] public string CategoryName { get; set; } = string.Empty;
    [Inject] private RecipeService RecipeService { get; set; } = default!;

    private IReadOnlyList<Recipe> Recipes = [];

    protected override void OnInitialized()
    {
        Recipes = RecipeService.GetByCategory(CategoryName);
    }
}

@page "/recipe/{RecipeId:int}"
@using RecipeHub.Models
@using RecipeHub.Services

<PageTitle>@(Recipe?.Title ?? "Recipe") — RecipeHub</PageTitle>

<nav aria-label="breadcrumb" class="mb-3">
    <ol class="breadcrumb">
        <li class="breadcrumb-item"><a href="/">Home</a></li>
        @if (Recipe is not null)
        {
            <li class="breadcrumb-item"><a href="category/@Recipe.Category">@Recipe.Category</a></li>
            <li class="breadcrumb-item active">@Recipe.Title</li>
        }
    </ol>
</nav>

@if (Recipe is null)
{
    <div class="alert alert-warning">Recipe not found.</div>
}
else
{
    <div class="d-flex align-items-center mb-3">
        <span class="fs-1 me-3">@Recipe.ImageUrl</span>
        <div>
            <h1 class="mb-0">@Recipe.Title</h1>
            <span class="badge bg-secondary">@Recipe.Category</span>
        </div>
    </div>

    <p class="lead">@Recipe.Description</p>

    <div class="row">
        <div class="col-md-4 mb-4">
            <div class="card">
                <div class="card-header"><strong>🥘 Ingredients</strong></div>
                <ul class="list-group list-group-flush">
                    @foreach (var ingredient in Recipe.Ingredients)
                    {
                        <li class="list-group-item">@ingredient</li>
                    }
                </ul>
            </div>
        </div>

        <div class="col-md-8 mb-4">
            <div class="card">
                <div class="card-header"><strong>📋 Steps</strong></div>
                <div class="card-body">
                    <ol>
                        @foreach (var step in Recipe.Steps)
                        {
                            <li class="mb-2">@step</li>
                        }
                    </ol>
                </div>
            </div>
        </div>
    </div>

    <div class="card mb-4">
        <div class="card-body">
            <h5>Rate this Recipe</h5>
            <p class="text-muted mb-2">
                ⭐ @Recipe.AverageRating.ToString("F1") average — @Recipe.TotalRatings ratings
            </p>
            <StarRating RecipeId="Recipe.Id" />
        </div>
    </div>
}

@code {
    [Parameter] public int RecipeId { get; set; }
    [Inject] private RecipeService RecipeService { get; set; } = default!;

    private Recipe? Recipe;

    protected override void OnInitialized()
    {
        Recipe = RecipeService.GetById(RecipeId);
    }
}

@rendermode InteractiveServer
@using RecipeHub.Services

<div class="d-inline-flex align-items-center">
    @for (int i = 1; i <= 5; i++)
    {
        var star = i;
        <button class="btn btn-link fs-4 p-0 me-1 text-decoration-none"
                @onclick="() => SubmitRating(star)"
                disabled="@HasRated"
                title="Rate @star star@(star > 1 ? "s" : "")">
            @(star <= HoverStar ? "★" : "☆")
        </button>
    }

    @if (HasRated)
    {
        <span class="ms-2 text-success">✓ Rated @SelectedStar star@(SelectedStar > 1 ? "s" : "")!</span>
    }
</div>

@code {
    [Parameter, EditorRequired] public int RecipeId { get; set; }
    [Inject] private RecipeService RecipeService { get; set; } = default!;

    private int HoverStar;
    private int SelectedStar;
    private bool HasRated;

    private void SubmitRating(int stars)
    {
        if (HasRated) return;
        RecipeService.AddRating(RecipeId, stars);
        SelectedStar = stars;
        HoverStar = stars;
        HasRated = true;
    }
}

@page "/submit"
@rendermode InteractiveServer
@using RecipeHub.Models
@using RecipeHub.Services

<PageTitle>Submit a Recipe — RecipeHub</PageTitle>

<h1>📝 Submit a Recipe</h1>
<p class="text-muted">Share your favorite recipe with the community.</p>

@if (Submitted)
{
    <div class="alert alert-success">
        <h4>🎉 Recipe submitted!</h4>
        <p>Your recipe "<strong>@Submission.Title</strong>" has been added to the @Submission.Category category.</p>
        <a href="category/@Submission.Category" class="btn btn-primary">View Category</a>
        <button class="btn btn-outline-secondary ms-2" @onclick="Reset">Submit Another</button>
    </div>
}
else
{
    <div class="row">
        <div class="col-md-8">
            <EditForm Model="Submission" OnValidSubmit="HandleSubmit" FormName="submitRecipe">
                <DataAnnotationsValidator />

                <div class="mb-3">
                    <label for="title" class="form-label">Recipe Title</label>
                    <InputText id="title" class="form-control" @bind-Value="Submission.Title"
                               placeholder="e.g., Grandma's Apple Pie" />
                </div>

                <div class="mb-3">
                    <label for="category" class="form-label">Category</label>
                    <InputSelect id="category" class="form-select" @bind-Value="Submission.Category">
                        <option value="">— Select a category —</option>
                        @foreach (var cat in Categories)
                        {
                            <option value="@cat">@cat</option>
                        }
                        <option value="Other">Other</option>
                    </InputSelect>
                </div>

                <div class="mb-3">
                    <label for="ingredients" class="form-label">Ingredients</label>
                    <InputTextArea id="ingredients" class="form-control" rows="5"
                                   @bind-Value="Submission.Ingredients"
                                   placeholder="One ingredient per line&#10;e.g.,&#10;2 cups flour&#10;1 cup sugar&#10;3 eggs" />
                    <div class="form-text">Enter one ingredient per line.</div>
                </div>

                <div class="mb-3">
                    <label for="steps" class="form-label">Steps</label>
                    <InputTextArea id="steps" class="form-control" rows="6"
                                   @bind-Value="Submission.Steps"
                                   placeholder="One step per line&#10;e.g.,&#10;Preheat oven to 350°F.&#10;Mix dry ingredients.&#10;Add wet ingredients and stir." />
                    <div class="form-text">Enter one step per line.</div>
                </div>

                @if (!string.IsNullOrEmpty(ErrorMessage))
                {
                    <div class="alert alert-danger">@ErrorMessage</div>
                }

                <button type="submit" class="btn btn-primary btn-lg">Submit Recipe</button>
            </EditForm>
        </div>
    </div>
}

@code {
    [Inject] private RecipeService RecipeService { get; set; } = default!;

    private RecipeSubmission Submission = new();
    private IReadOnlyList<string> Categories = [];
    private bool Submitted;
    private string? ErrorMessage;

    protected override void OnInitialized()
    {
        Categories = RecipeService.GetCategories();
    }

    private void HandleSubmit()
    {
        if (string.IsNullOrWhiteSpace(Submission.Title) ||
            string.IsNullOrWhiteSpace(Submission.Category) ||
            string.IsNullOrWhiteSpace(Submission.Ingredients) ||
            string.IsNullOrWhiteSpace(Submission.Steps))
        {
            ErrorMessage = "Please fill in all fields.";
            return;
        }

        RecipeService.AddRecipe(Submission);
        Submitted = true;
        ErrorMessage = null;
    }

    private void Reset()
    {
        Submission = new();
        Submitted = false;
        ErrorMessage = null;
    }
}

