toolArgs.file_text:
@page "/submit"
@rendermode InteractiveServer
@using RecipeHub.Models
@using RecipeHub.Services

<PageTitle>Submit a Recipe — RecipeHub</PageTitle>

<h1>📝 Submit a Recipe</h1>
<p class="text-muted">Share your favorite recipe with the community.</p>

@if (Submitted)
{
    <div class="alert alert-success">
        <h4>🎉 Recipe submitted!</h4>
        <p>Your recipe "<strong>@Submission.Title</strong>" has been added to the @Submission.Category category.</p>
        <a href="category/@Submission.Category" class="btn btn-primary">View Category</a>
        <button class="btn btn-outline-secondary ms-2" @onclick="Reset">Submit Another</button>
    </div>
}
else
{
    <div class="row">
        <div class="col-md-8">
            <EditForm Model="Submission" OnValidSubmit="HandleSubmit" FormName="submitRecipe">
                <DataAnnotationsValidator />

                <div class="mb-3">
                    <label for="title" class="form-label">Recipe Title</label>
                    <InputText id="title" class="form-control" @bind-Value="Submission.Title"
                               placeholder="e.g., Grandma's Apple Pie" />
                </div>

                <div class="mb-3">
                    <label for="category" class="form-label">Category</label>
                    <InputSelect id="category" class="form-select" @bind-Value="Submission.Category">
                        <option value="">— Select a category —</option>
                        @foreach (var cat in Categories)
                        {
                            <option value="@cat">@cat</option>
                        }
                        <option value="Other">Other</option>
                    </InputSelect>
                </div>

                <div class="mb-3">
                    <label for="ingredients" class="form-label">Ingredients</label>
                    <InputTextArea id="ingredients" class="form-control" rows="5"
                                   @bind-Value="Submission.Ingredients"
                                   placeholder="One ingredient per line&#10;e.g.,&#10;2 cups flour&#10;1 cup sugar&#10;3 eggs" />
                    <div class="form-text">Enter one ingredient per line.</div>
                </div>

                <div class="mb-3">
                    <label for="steps" class="form-label">Steps</label>
                    <InputTextArea id="steps" class="form-control" rows="6"
                                   @bind-Value="Submission.Steps"
                                   placeholder="One step per line&#10;e.g.,&#10;Preheat oven to 350°F.&#10;Mix dry ingredients.&#10;Add wet ingredients and stir." />
                    <div class="form-text">Enter one step per line.</div>
                </div>

                @if (!string.IsNullOrEmpty(ErrorMessage))
                {
                    <div class="alert alert-danger">@ErrorMessage</div>
                }

                <button type="submit" class="btn btn-primary btn-lg">Submit Recipe</button>
            </EditForm>
        </div>
    </div>
}

@code {
    [Inject] private RecipeService RecipeService { get; set; } = default!;

    private RecipeSubmission Submission = new();
    private IReadOnlyList<string> Categories = [];
    private bool Submitted;
    private string? ErrorMessage;

    protected override void OnInitialized()
    {
        Categories = RecipeService.GetCategories();
    }

    private void HandleSubmit()
    {
        if (string.IsNullOrWhiteSpace(Submission.Title) ||
            string.IsNullOrWhiteSpace(Submission.Category) ||
            string.IsNullOrWhiteSpace(Submission.Ingredients) ||
            string.IsNullOrWhiteSpace(Submission.Steps))
        {
            ErrorMessage = "Please fill in all fields.";
            return;
        }

        RecipeService.AddRecipe(Submission);
        Submitted = true;
        ErrorMessage = null;
    }

    private void Reset()
    {
        Submission = new();
        Submitted = false;
        ErrorMessage = null;
    }
}

